    <div class="container">
        <div class="header">
            <h1>IT Ticket Dashboard 2026</h1>
            <p id="lastUpdated">Last Updated: April 2026</p>
        </div>

        <div class="summary-cards">
            <div class="card">
                <h3>Total Tickets</h3>
                <div class="value" id="totalTickets">0</div>
            </div>
            <div class="card">
                <h3>Resolved / Closed</h3>
                <div class="value" id="resolvedTickets">0</div>
            </div>
            <div class="card">
                <h3>Pending</h3>
                <div class="value" id="pendingTickets">0</div>
            </div>
        </div>

        <div class="charts-grid">
            <div class="chart-card">
                <h2>Resolution Progress</h2>
                <canvas id="resolutionChart"></canvas>
            </div>
            <div class="chart-card">
                <h2>Workload by Agent Group</h2>
                <canvas id="agentChart"></canvas>
            </div>
            <div class="chart-card">
                <h2>Top Issue Categories</h2>
                <canvas id="categoryChart"></canvas>
            </div>
            <div class="chart-card">
                <h2>Status Distribution</h2>
                <canvas id="statusChart"></canvas>
            </div>
            <div class="chart-card">
                <h2>BU Distribution (Top 5)</h2>
                <canvas id="buChart"></canvas>
            </div>
        </div>

        <div class="chart-card" style="margin-top: 20px;">
            <h2>Recent Tickets Raw Data</h2>
            <div style="overflow-x: auto;">
                <table id="ticketTable">
                    <thead>
                        <tr>
                            <th>ID</th>
                            <th>Subject</th>
                            <th>Status</th>
                            <th>Category</th>
                            <th>BU Name</th>
                        </tr>
                    </thead>
                    <tbody></tbody>
                </table>
            </div>
        </div>
    </div>

    <script>
        async function loadDashboard() {
            const response = await fetch('data.json');
            const data = await response.json();

            // 1. Total Metrics
            document.getElementById('totalTickets').textContent = data.length;
            const resolvedCount = data.filter(t => t.Status === 'Closed' || t.Status === 'Resolved').length;
            document.getElementById('resolvedTickets').textContent = resolvedCount;
            document.getElementById('pendingTickets').textContent = data.length - resolvedCount;

            // 2. Data Processing for Charts
            const agentCounts = {};
            const categoryCounts = {};
            const statusCounts = {};
            const buCounts = {};

            data.forEach(t => {
                agentCounts[t['Agent Name']] = (agentCounts[t['Agent Name']] || 0) + 1;
                categoryCounts[t['Category']] = (categoryCounts[t['Category']] || 0) + 1;
                statusCounts[t['Status']] = (statusCounts[t['Status']] || 0) + 1;
                buCounts[t['BU Name']] = (buCounts[t['BU Name']] || 0) + 1;
            });

            const topAgents = Object.entries(agentCounts).sort((a, b) => b[1] - a[1]).slice(0, 5);
            const topCategories = Object.entries(categoryCounts).sort((a, b) => b[1] - a[1]).slice(0, 5);
            const topBUs = Object.entries(buCounts).sort((a, b) => b[1] - a[1]).slice(0, 5);

            // 3. Render Charts
            new Chart(document.getElementById('agentChart'), {
                type: 'bar',
                data: {
                    labels: topAgents.map(a => a[0]),
                    datasets: [{ label: 'Tickets', data: topAgents.map(a => a[1]), backgroundColor: '#3498db' }]
                },
                options: { indexAxis: 'y' }
            });

            new Chart(document.getElementById('categoryChart'), {
                type: 'bar',
                data: {
                    labels: topCategories.map(c => c[0]),
                    datasets: [{ label: 'Tickets', data: topCategories.map(c => c[1]), backgroundColor: '#e74c3c' }]
                }
            });

            new Chart(document.getElementById('statusChart'), {
                type: 'doughnut',
                data: {
                    labels: Object.keys(statusCounts),
                    datasets: [{ data: Object.values(statusCounts), backgroundColor: ['#2ecc71', '#f1c40f', '#e67e22', '#95a5a6'] }]
                }
            });

            new Chart(document.getElementById('buChart'), {
                type: 'pie',
                data: {
                    labels: topBUs.map(b => b[0]),
                    datasets: [{ data: topBUs.map(b => b[1]), backgroundColor: ['#9b59b6', '#34495e', '#16a085', '#27ae60', '#d35400'] }]
                }
            });

            // 4. Fill Table
            const tbody = document.querySelector('#ticketTable tbody');
            data.slice(0, 10).forEach(t => {
                const tr = document.createElement('tr');
                tr.innerHTML = `<td>${t.ID}</td><td>${t.Subject}</td><td>${t.Status}</td><td>${t.Category}</td><td>${t['BU Name']}</td>`;
                tbody.appendChild(tr);
            });
        }

        loadDashboard();
    </script>
</body>

</html>

